function Products(t){var e=this;t.history;this.getScrollInterval=function(){return $(document).width()<500?"150px":"336px"},this.loadOnReady=function(){$(".horizon-prev").click(function(){event.preventDefault(),$(this).closest(".scroll-scope").find(".ul-panel").stop().animate({scrollLeft:"-="+e.getScrollInterval()},"slow")}),$(".horizon-next").click(function(){event.preventDefault(),$(this).closest(".scroll-scope").find(".ul-panel").stop().animate({scrollLeft:"+="+e.getScrollInterval()},"slow")})}}